  { question: 'What is the scope?', header: 'Scope', options: [
    { label: 'Single file', description: '1 file change' },
    { label: 'Module', description: 'One module' },
    { label: 'Cross-module', description: 'Multiple modules' },
    { label: 'System', description: 'System-wide' }
  ]},
  { question: 'Any constraints?', header: 'Constraints', options: [
